3	const cellKey = ([x, y]: Cell): string => `${x},${y}`;
4	
5	const NEIGHBOR_OFFSETS: ReadonlyArray<Cell> = [
6	  [-1, -1], [-1, 0], [-1, 1],
7	  [ 0, -1],          [ 0, 1],
8	  [ 1, -1], [ 1, 0], [ 1, 1],
9	];
10	
11	const neighborsOf = ([x, y]: Cell): Cell[] =>
12	  NEIGHBOR_OFFSETS.map(([dx, dy]) => [x + dx, y + dy]);
13	
14	const countLiveNeighbors = (cell: Cell, liveSet: ReadonlySet<string>): number =>
15	  neighborsOf(cell).filter((n) => liveSet.has(cellKey(n))).length;
16	
17	const isAliveNextGeneration = (cell: Cell, liveSet: ReadonlySet<string>): boolean => {
18	  const n = countLiveNeighbors(cell, liveSet);
19	  const isCurrentlyAlive = liveSet.has(cellKey(cell));
20	  return n === 3 || (isCurrentlyAlive && n === 2);
21	};
22	
23	export function nextGeneration(liveCells: readonly Cell[]): Cell[] {
24	  const liveSet = new Set(liveCells.map(cellKey));
25	
26	  const candidates = new Map<string, Cell>();
27	  for (const cell of liveCells) {
28	    for (const candidate of [cell, ...neighborsOf(cell)]) {
29	      candidates.set(cellKey(candidate), candidate);
30	    }
31	  }
32	
33	  return [...candidates.values()].filter((cell) => isAliveNextGeneration(cell, liveSet));
34	}
